// ============ HELPER FUNCTIONS ============
import type { DailyTip, ParentingStory, OfflineActivity, ParentingResource } from '@/data/parentingContent';

export function getTranslatedTips(tips: DailyTip[], lang: Language): DailyTip[] {
  if (lang === 'en' || lang === 'es' || lang === 'fr') return tips;
  const translations = dailyTipTranslations[lang];
  if (!translations) return tips;
  return tips.map(tip => {
    const t = translations[tip.id];
    if (!t) return tip;
    return { ...tip, tip: t.tip || tip.tip, category: t.category || tip.category };
  });
}

export function getTranslatedStories(stories: ParentingStory[], lang: Language): ParentingStory[] {
  if (lang === 'en' || lang === 'es' || lang === 'fr') return stories;
  const translations = storyTranslations[lang];
  if (!translations) return stories;
  return stories.map(story => {
    const t = translations[story.id];
    if (!t) return story;
    return {
      ...story,
      title: t.title || story.title,
      story: t.story || story.story,
      moral: t.moral || story.moral,
      ageGroup: t.ageGroup || story.ageGroup,
    };
  });
}

export function getTranslatedActivities(activities: OfflineActivity[], lang: Language): OfflineActivity[] {
  if (lang === 'en' || lang === 'es' || lang === 'fr') return activities;
  const translations = activityTranslations[lang];
  if (!translations) return activities;
  return activities.map(act => {
    const t = translations[act.id];
    if (!t) return act;
    return {
      ...act,
      title: t.title || act.title,
      description: t.description || act.description,
      materials: t.materials || act.materials,
    };
  });
}

export function getTranslatedResources(resources: ParentingResource[], lang: Language): ParentingResource[] {
  if (lang === 'en' || lang === 'es' || lang === 'fr') return resources;
  const translations = resourceTranslations[lang];
  if (!translations) return resources;
  return resources.map(res => {
    const t = translations[res.id];
    if (!t) return res;
    return {
      ...res,
      title: t.title || res.title,
      description: t.description || res.description,
      category: t.category || res.category,
    };
  });
}
